import random
from enum import Enum, auto

class Move(Enum):
    ROCK = auto()
    PAPER = auto()
    SCISSORS = auto()

def beats(a, b):
    return ((a == Move.ROCK and b == Move.SCISSORS) or
            (a == Move.PAPER and b == Move.ROCK) or
            (a == Move.SCISSORS and b == Move.PAPER))

class Player:
    def __init__(self, name, strategy=None):
        self.name = name
        self.strategy = strategy or (lambda: random.choice(list(Move)))
        self.wins = 0
        self.losses = 0

    def play(self):
        move = self.strategy()
        return move

class Arena:
    def __init__(self, p1, p2):
        self.p1 = p1
        self.p2 = p2

    def match(self):
        m1 = self.p1.play()
        m2 = self.p2.play()
        result = "draw"
        if beats(m1, m2): result = self.p1.name + " wins"
        elif beats(m2, m1): result = self.p2.name + " wins"
        else: result = "draw"

        if result == self.p1.name + " wins": self.p1.wins += 1
        elif result == self.p2.name + " wins": self.p2.losses += 1

        return { "p1": m1, "p2": m2, "result": result }

class Tournament:
    def __init__(self, players, best_of=3):
        self.players = players
        self.best_of = best_of

    def run_round_robin(self):
        print(f"Starting best-of-{self.best_of} round-robin...")
        for i in range(len(self.players)):
            for j in range(i + 1, len(self.players)):
                arena = Arena(self.players[i], self.players[j])
                wins_p1, wins_p2 = 0, 0
                while wins_p1 < (self.best_of // 2) + 1 and wins_p2 < (self.best_of // 2) + 1:
                    r = arena.match()
                    if self.players[i].name in r["result"] and "wins" in r["result"]:
                        wins_p1 += 1
                    elif self.players[j].name in r["result"] and "wins" in r["result"]:
                        wins_p2 += 1
                    print(f"  {self.players[i].name} vs {self.players[j].name}: {r['result']}")
                print(f"Score: {self.players[i].name} {wins_p1} - {wins_p2} {self.players[j].name}\n")

if __name__ == "__main__":
    p1 = Player("RockBot", lambda: Move.ROCK)
    p2 = Player("PaperMaster", lambda: Move.PAPER)
    p3 = Player("Randomizer", lambda: random.choice(list(Move)))
    p4 = Player("CopyCat", lambda: p1.strategy()) # Copy p1's last decision

    tourney = Tournament([p1, p2, p3, p4], best_of=5)
    tourney.run_round_robin()

    sorted_players = sorted(tourney.players, key=lambda x: x.wins, reverse=True)
    print("Tournament Standings:")
    for i, player in enumerate(sorted_players, 1):
        print(f"{i}. {player.name} ({player.wins} wins)")

