function x = lu_no_pivot(A, b)
    [n, m] = size(A);
    L = eye(n);
    U = A;

    % Forward elimination WITHOUT row swapping
    for k = 1:n-1
        for i = k+1:n
            if U(k,k) == 0
                error('Pivot zero encountered without pivoting.');
            end
            mult = U(i,k) / U(k,k);
            U(i, k:end) = U(i, k:end) - mult * U(k, k:end);
            L(i,k) = mult;
        end
    end

    % Forward substitution: L * y = b
    y = zeros(n, 1);
    for i = 1:n
        y(i) = b(i) - L(i, 1:i-1) * y(1:i-1);
    end

    % Back substitution: U * x = y
    x = zeros(n, 1);
    for i = n:-1:1
        x(i) = (y(i) - U(i, i+1:n) * x(i+1:n)) / U(i, i);
    end
end

